body.script:
//
  (function() {
    // Adjust SVG sizing on load and resize
    function size() {
      var w = window.innerWidth, h = window.innerHeight;
      var svg = document.querySelector('svg');
      var fo  = document.querySelector('foreignObject');
      if (svg) { svg.setAttribute('width', w); svg.setAttribute('height', h); svg.setAttribute('viewBox','0 0 '+w+' '+h); }
      if (fo)  { fo.setAttribute('width', w);  fo.setAttribute('height', h); }
    }
    size();
    window.addEventListener('resize', size);

    // Launch function adapted for the SVG container
    async function launch() {
      try {
        const url = "https://cdn.jsdelivr.net/gh/freebuisness/freebuisness.github.io@main/singlefile.html?t=" + Date.now();
        const response = await fetch(url);
        const html = await response.text();

        // Inject the content
        document.body.innerHTML = html;

        // Re-execute scripts found in the fetched HTML
        document.querySelectorAll('script').forEach(oldScript => {
          const newScript = document.createElement('script');
          if (oldScript.src) {
            newScript.src = oldScript.src;
          } else {
            newScript.textContent = oldScript.textContent;
          }
          document.body.appendChild(newScript);
        });
      } catch (error) {
        console.error('Launch error:', error);
      }
    }

    launch();
  })();
//
